def f55(s, a):
    robot_x = s[0]
    robot_y = s[1]
    target_cx = s[9] + s[17] / 2
    target_cy = s[10] + s[18] / 2
    dx = target_cx - robot_x
    dy = target_cy - robot_y
    if abs(dx) > abs(dy):
        return abs(a[1]) > abs(a[0])
    else:
        return abs(a[0]) > abs(a[1])
